// 초기화 파라미터 설정
object initializeParameter = null;

// 라이브러리 초기화
var device = new DeviceMeasurementVirtual();
if (device.Initialize(initializeParameter) == false)
{
    // 초기화 실패
    return;
}

// 라이브러리 정리
device.DeInitialize();
return;

var device = new DeviceMeasurementVirtual();
// DLL 버전 정보 읽기
string version = device.GetVersion(bReflesh: true);
Console.WriteLine($"DLL 버전: {version}");
return;

// 초기화 파라미터 설정
object initializeParameter = null;

// 라이브러리 초기화
var device = new DeviceMeasurementVirtual();
if (device.Initialize(initializeParameter) == false)
{
    // 초기화 실패
    return;
}

// 통신 준비 상태 확인
bool bIsOpened = device.IsOpened();
Console.WriteLine($"통신 준비 상태: {bIsOpened}");

// 라이브러리 정리
device.DeInitialize();
return;

// 초기화 파라미터 설정
object initializeParameter = null;

// 라이브러리 초기화
var device = new DeviceMeasurementVirtual();
if (device.Initialize(initializeParameter) == false)
{
    // 초기화 실패
    return;
}

// 단일 채널 읽기
int slaveIndex = 0;
int channelIndex = 0;
double readValue;
if (device.TryReadOneChannel(slaveIndex, channelIndex, out readValue) == true)
{
    // 읽기에 성공한 경우
    Console.WriteLine($"읽은 값: {readValue:0.0000}");
}

// 라이브러리 정리
device.DeInitialize();
return;

// 초기화 파라미터 설정
object initializeParameter = null;

// 라이브러리 초기화
var device = new DeviceMeasurementVirtual();
if (device.Initialize(initializeParameter) == false)
{
    // 초기화 실패
    return;
}

// 모든 채널 읽기
int slaveIndex = 0;
double[] readValues;
if (device.TryReadAllChannels(slaveIndex, out readValues) == true)
{
    // 읽기에 성공한 경우
    Console.WriteLine($"읽은 값: {{ {string.Join(", ", readValues.Select(i => $"{i:0.0000}"))} }}");
}

// 라이브러리 정리
device.DeInitialize();
return;

