object initializeParameter = null;

// 라이브러리 초기화
var device = new DeviceMeasurementVirtual();
if (device.Initialize(initializeParameter) == false)
{
    // 초기화 실패
    return;
}

// 연속되지 않은 여러 채널 읽기
int slaveIndex = 0;
int[] channelIndexes = new int[] { 0, 2, 4, 6 };
double[] readValues;
if (device.TryReadRandomChannels(slaveIndex, channelIndexes, out readValues) == true)
{
    // 읽기에 성공한 경우
    Console.WriteLine($"읽은 값: {{ {string.Join(", ", readValues.Select(i => $"{i:0.0000}"))} }}");
}

// 라이브러리 정리
device.DeInitialize();
return;

// 초기화 파라미터 설정
object initializeParameter = null;

// 라이브러리 초기화
var device = new DeviceMeasurementVirtual();
if (device.Initialize(initializeParameter) == false)
{
    // 초기화 실패
    return;
}

// 연속된 여러 채널 읽기
int slaveIndex = 0;
int startIndex = 3;
int count = 2;
double[] readValues;
if (device.TryReadSequncialChannels(slaveIndex, startIndex, count, out readValues) == true)
{
    // 읽기에 성공한 경우
    Console.WriteLine($"읽은 값: {{ {string.Join(", ", readValues.Select(i => $"{i:0.0000}"))} }}");
}

// 라이브러리 정리
device.DeInitialize();
return;
